SELECT pa.answer_id, pa.question_id, pa.user_id, pa.answer_date, pa.answer_text
FROM product_answers pa
WHERE pa.answer_id = 1;

SELECT COUNT(DISTINCT c.email)
FROM customers c
JOIN product_reviews pr ON c.customer_id = pr.customer_id;

SELECT DISTINCT sizes.size_name
FROM sizes
INNER JOIN products ON sizes.size_id = products.size_id;

SELECT p.product_name
FROM products p
WHERE p.product_id NOT IN (SELECT i.product_id FROM inventory i);

SELECT pr.review_text
FROM product_reviews pr
JOIN products p ON pr.product_id = p.product_id
WHERE p.product_rating = (
    SELECT MAX(product_rating) FROM products
);
